function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, s, e] of edges) {
        adj[u].push([v, s, e]);
    }

    // Distance array
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;

    // Priority queue (min-heap)
    class PriorityQueue {
        constructor() {
            this.heap = [];
        }

        push(value) {
            this.heap.push(value);
            this.bubbleUp();
        }

        pop() {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.bubbleDown();
            return min;
        }

        bubbleUp() {
            let index = this.heap.length - 1;
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[index][0] < this.heap[parentIndex][0]) {
                    [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }

        bubbleDown() {
            let index = 0;
            while (true) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
                    smallest = left;
                }
                if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
                    smallest = right;
                }
                if (smallest !== index) {
                    [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                    index = smallest;
                } else {
                    break;
                }
            }
        }

        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.push([0, 0]);

    while (!pq.isEmpty()) {
        const [current_time, node] = pq.pop();
        if (node === n - 1) {
            return current_time;
        }
        if (current_time > dist[node]) {
            continue;
        }
        for (const [v, s, e] of adj[node]) {
            const earliest_time = Math.max(current_time, s);
            if (earliest_time <= e) {
                const new_time = earliest_time + 1;
                if (new_time < dist[v]) {
                    dist[v] = new_time;
                    pq.push([new_time, v]);
                }
            }
        }
    }

    return -1;
}
